B.Ul=new A.rY(["Rafael Torres","\ud83c\uddec\ud83c\udde7","Londres \xb7 Reino Unido","Advocacia","Dra. Beatriz Lima",5,"A Beatriz me orientou no processo de visto de forma incr\xedvel. Resolveu tudo remotamente, sem burocracia. N\xe3o precisei sair de casa. Melhor investimento que fiz desde que cheguei aqui.","h\xe1 5 dias",B.ad])
